pre.code:
import { I18n, boot } from 'metaowl'

await I18n.load({
  locale: 'de',
  messages: {
    welcome: 'Willkommen, {name}!',
    goodbye: 'Auf Wiedersehen!',
    items: '{count, plural, one {# Artikel} other {# Artikel}}',
  },
})

boot()

import { I18n } from 'metaowl'

// Simple translation
I18n.t('goodbye')              // "Auf Wiedersehen!"

// With interpolation
I18n.t('welcome', { name: 'Max' })   // "Willkommen, Max!"

// With pluralization
I18n.t('items', { count: 1 })  // "1 Artikel"
I18n.t('items', { count: 5 })  // "5 Artikel"

// Number formatting
I18n.n(1234.5, 'currency')   // "€1.234,50"

// Date formatting
I18n.d(new Date(), 'short')  // "18.03.2026"

await I18n.load({
  locale: 'de',
  messages: { ... },
  numberFormats: {
    currency: { style: 'currency', currency: 'EUR' },
  },
  dateFormats: {
    short: { day: '2-digit', month: '2-digit', year: 'numeric' },
    long:  { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' },
  },
})
